const OpenAI = require('openai');
const { Pinecone } = require('@pinecone-database/pinecone');

async function embedAndUpsert({ texts, namespace = 'default', indexName }) {
  const openai = new OpenAI();
  const pc = new Pinecone();
  const index = pc.index(indexName);

  const response = await openai.embeddings.create({
    model: 'text-embedding-3-small',
    input: texts
  });

  const vectors = response.data.map((item, i) => ({
    id: `vec_${Date.now()}_${i}`,
    values: item.embedding,
    metadata: { text: texts[i] }
  }));

  await index.namespace(namespace).upsert(vectors);
  return { upserted: vectors.length, namespace };
}

module.exports = { embedAndUpsert };

const OpenAI = require('openai');
const { Pinecone } = require('@pinecone-database/pinecone');

async function search({ query, indexName, namespace = 'default', topK = 5 }) {
  const openai = new OpenAI();
  const pc = new Pinecone();

  const embedding = await openai.embeddings.create({
    model: 'text-embedding-3-small',
    input: query
  });

  const results = await pc.index(indexName).namespace(namespace).query({
    vector: embedding.data[0].embedding,
    topK,
    includeMetadata: true
  });

  return results.matches.map(m => ({ id: m.id, score: m.score, text: m.metadata?.text }));
}

module.exports = { search };
